const text = $json.message.text || '';
const parts = text.trim().split(/\s+/);
const command = parts[0].toLowerCase().replace('/', '');
const args = parts.slice(1).join(' ');

return [{
  json: {
    chat_id: $json.message.chat.id,
    command: command,
    args: args,
    source: 'command'
  }
}];

const chatId = $json.message.chat.id;
const content = $json.message.text || '';

return [{
  json: {
    chat_id: chatId,
    content: content,
    source: 'text'
  }
}];

// 1. Get Session from the node immediately preceding this path
const session = $('Get or Create Session').first().json;

// 2. Get User Input safely from the Trigger
const triggerData = $('Telegram Trigger').first().json;
const userContent = triggerData.message.text || 
                    (triggerData.message.voice ? "Voice Message" : "Unknown Input");

let finalContent = userContent;
try {
  const transcription = $('Transcribe Voice').first().json.text;
  if (transcription) finalContent = transcription;
} catch (e) {}

// 3. Build history - REDUCED to last 5 messages
const historyArray = (session.messages || []).slice(-5).map(m => ({
  role: m.role === 'user' ? 'user' : 'assistant',
  content: m.content
}));

const historyText = historyArray
  .map(m => `${m.role.toUpperCase()}: ${m.content}`)
  .join('\n\n');

return [{
  json: {
    session_id: session.id,
    chat_id: triggerData.message.chat.id,
    current_message: finalContent,
    conversation_history: historyText,
    history_array: historyArray,
    message_count: historyArray.length,
    // Flag that we need to fetch living context
    needs_living_context: true
  }
}];

// 1. Grab the Agent's output directly from the input data
// In a Code node, the data from the previous node is available in the first item
const agentOutput = (items && items.length > 0) ? items[0].json.output : null;

// 2. Access 'Build Agent Context' using the .first() method 
// which is the most stable way to pull "backwards" in a workflow.
const context = $('Build Agent Context').first().json;

if (!agentOutput) {
  throw new Error("The Agent did not return any output.");
}

return [{
  json: {
    response: agentOutput,
    session_id: context.session_id,
    chat_id: context.chat_id
  }
}];

// Ensure we are grabbing the first item from the linked nodes to avoid indexing hangs
const session = $('Get Session for End').first().json;
const chatId = $('Parse Command').first().json.chat_id;

// Use optional chaining for safety
const messageCount = (session.messages || []).length;

if (messageCount < 2) {
  return [{ 
    json: { 
      skip_extraction: true, 
      chat_id: chatId, 
      message: 'No conversation to save.' 
    } 
  }];
}

return [{
  json: {
    skip_extraction: false,
    session_id: session.id,
    chat_id: chatId,
    transcript: $json.data, // Accessing the specific 'data' field from your input
    message_count: messageCount,
    title: `Telegram Chat - ${new Date().toLocaleDateString('en-NZ', { 
      day: 'numeric', 
      month: 'short', 
      year: 'numeric', 
      hour: '2-digit', 
      minute: '2-digit' 
    })}`
  }
}];

