const tasks = $input.all().map(i => i.json);
const chatId = $('Parse Command').item.json.chat_id;

if (!tasks.length) {
  return [{ json: { text: 'No open tasks!', chat_id: chatId } }];
}

const emoji = { immediate: '🔴', this_week: '🟠', soon: '🟡', someday: '⚪' };
const lines = tasks.map(t => `${emoji[t.urgency] || '⚪'} ${t.task}`);

return [{
  json: {
    text: `Open Tasks\n\n${lines.join('\n')}`,
    chat_id: chatId
  }
}];

const memories = $input.all().map(i => i.json);
const chatId = $('Parse Command')?.item?.json?.chat_id || 0;

const clean = (text) => {
  if (!text) return '';
  return text.toString().replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
};

if (!memories.length) {
  return [{ json: { text: 'No memories yet.', chat_id: chatId } }];
}

const lines = memories.map(m => {
  const date = new Date(m.created_at).toLocaleDateString('en-NZ', { day: 'numeric', month: 'short' });
  const title = clean(m.title || 'Untitled');
  return `• <b>${title}</b> (${date})`;
});

return [{
  json: {
    text: `<b>Recent Memories</b>\n\n${lines.join('\n')}`,
    chat_id: chatId
  }
}];

// 1. Get the transcript from the earlier node
const prepareNode = $('Prepare for Extraction').first().json;

// 2. Get the context from the node directly before this one
// Changed from 'Get Current Living Context' to 'Get Living Context Info'
const contextNode = $('Get Living Context Info').first().json;

// Extract values safely
const transcript = prepareNode.transcript || "";
const currentContext = contextNode.raw || {};

// If transcript is missing, stop to prevent prompt errors
if (!transcript) {
  return [{ json: { error: "No transcript found", skip: true } }];
}

return [{
  json: {
    prompt: `You are updating a "Living Context Document" that captures evolving beliefs, patterns, and direction.

## Current Living Context:
${JSON.stringify(currentContext, null, 2)}

## New Conversation Just Ended:
${transcript.substring(0, 8000)}

## Your Task:
Analyze this conversation and determine what (if anything) should be updated in the Living Context.

Rules:
1. Only update fields where the conversation provides NEW or CHANGED information
2. For arrays (patterns, skills, threads), ADD new items don't replace unless something is explicitly contradicted
3. Be concise - each field should be 1-2 sentences max
4. If nothing relevant was discussed, return {"no_update": true}

Return a JSON object with ONLY the fields that need updating. Example:
{
  "business_hypotheses": {
    "whats_unclear": "Whether to focus on B2B or B2C first"
  },
  "active_threads": ["Evaluating pricing models", "Building living context system"],
  "patterns": {
    "repeated_energizers": ["Deep technical implementation", "System architecture"]
  }
}

Return ONLY valid JSON, no explanation.`,
    current_context: currentContext
  }
}];

// 1. Navigate the deep nesting of the LLM output
// It looks like: output[0].content[0].text
const rawData = $json.output?.[0]?.content?.[0]?.text || $json.text || $json.output;

const currentContextNode = $('Prepare Update Prompt').first().json;
const currentContext = currentContextNode.current_context;

try {
  let update;

  // 2. Logic to handle if data is ALREADY an object or still a string
  if (typeof rawData === 'string') {
    const cleanJson = rawData.replace(/```json|```/g, "").trim();
    update = JSON.parse(cleanJson);
  } else {
    update = rawData; // It's already an object, no parsing needed
  }

  // If no update needed, skip
  if (!update || update.no_update === true) {
    return [{ json: { skip_update: true, message: "No relevant updates found by AI." } }];
  }

  // Merge arrays intelligently
  const mergeArrays = (current, update) => {
    const base = Array.isArray(current) ? current : [];
    const adds = Array.isArray(update) ? update : [];
    if (adds.length === 0) return base;
    return [...new Set([...base, ...adds])];
  };

  // Build the update payload
  const payload = {};

  if (update.business_hypotheses) {
    payload.p_business_hypotheses = {
      ...(currentContext.business_hypotheses || {}),
      ...update.business_hypotheses
    };
  }

  if (update.directional_summary) {
    payload.p_directional_summary = {
      ...(currentContext.directional_summary || {}),
      ...update.directional_summary
    };
  }

  if (update.patterns) {
    payload.p_patterns = {
      repeated_failures: mergeArrays(
        currentContext.patterns?.repeated_failures,
        update.patterns?.repeated_failures
      ),
      repeated_energizers: mergeArrays(
        currentContext.patterns?.repeated_energizers,
        update.patterns?.repeated_energizers
      ),
      repeated_blockers: mergeArrays(
        currentContext.patterns?.repeated_blockers,
        update.patterns?.repeated_blockers
      )
    };
  }

  if (update.identity_notes) {
    payload.p_identity_notes = {
      skills_compounding: mergeArrays(
        currentContext.identity_notes?.skills_compounding,
        update.identity_notes?.skills_compounding
      ),
      values_emerging: mergeArrays(
        currentContext.identity_notes?.values_emerging,
        update.identity_notes?.values_emerging
      )
    };
  }

  if (update.active_threads) {
    payload.p_active_threads = update.active_threads;
  }

  payload.p_user_id = 'zane';

  return [{ json: { skip_update: false, payload } }];

} catch (e) {
  return [{ 
    json: { 
      skip_update: true, 
      error: "Processing Failed", 
      message: e.message,
      data_type: typeof rawData
    } 
  }];
}

const text = $json.response;
const chatId = $json.chat_id;
const MAX_LENGTH = 4000;

if (!text) return [];

// Convert Markdown to Telegram HTML
let html = text
  // Code blocks first (before other formatting)
  .replace(/```[\w]*\n?([\s\S]*?)```/g, '<pre>$1</pre>')
  // Inline code
  .replace(/`([^`]+)`/g, '<code>$1</code>')
  // Bold: **text** or __text__
  .replace(/\*\*(.+?)\*\*/g, '<b>$1</b>')
  .replace(/__(.+?)__/g, '<b>$1</b>')
  // Italic: *text* or _text_ (but not inside words)
  .replace(/(?<!\w)\*([^*]+)\*(?!\w)/g, '<i>$1</i>')
  .replace(/(?<!\w)_([^_]+)_(?!\w)/g, '<i>$1</i>')
  // Strikethrough
  .replace(/~~(.+?)~~/g, '<s>$1</s>')
  // Links
  .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Headers become bold
  .replace(/^#{1,6}\s+(.+)$/gm, '<b>$1</b>');

// Split into chunks
const chunks = [];
let currentPos = 0;

while (currentPos < html.length) {
  let endPos = currentPos + MAX_LENGTH;

  if (endPos < html.length) {
    const lastNewline = html.lastIndexOf('\n', endPos);
    const lastSpace = html.lastIndexOf(' ', endPos);
    endPos = (lastNewline > currentPos) ? lastNewline : (lastSpace > currentPos ? lastSpace : endPos);
  }

  chunks.push({
    json: {
      chat_id: chatId,
      response_chunk: html.substring(currentPos, endPos).trim()
    }
  });

  currentPos = endPos;
}

return chunks;
